import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/blog.md","filePath":"hi/Other/blog.md","lastUpdated":1781962217000}'),n={name:"hi/Other/blog.md"};function r(c,e,d,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature आपके ImgBed site में एक standalone blog page जोड़ता है।</p><p>Enable करने के बाद visitors यह खोल सकते हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>Blog open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project से adapted है। ImgBed इसे rewrite करके Vue के साथ integrate करता है, ताकि यह image hosting site का हिस्सा बनकर चल सके।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Blog settings यहाँ हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Enable</code> on करें।</li><li>Blog configuration store करने के लिए GitHub account select करें।</li><li><code>Update Blog</code> पर click करें।</li><li>Success message आने तक इंतज़ार करें।</li><li>Blog देखने के लिए <code>https://your-domain.com/blog/</code> खोलें।</li></ol><p>पहली बार इस्तेमाल करते समय ImgBed selected account के तहत एक private GitHub repository तैयार करता है:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>यह repository blog settings और article content store करती है।</p><h2 id="posts-लिखना" tabindex="-1">Posts लिखना <a class="header-anchor" href="#posts-लिखना" aria-label="Permalink to &quot;Posts लिखना&quot;">​</a></h2><p>Blog posts अपनी private GitHub repository में edit करें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>GitHub खोलें।</li><li>Private <code>imgbed-blog-config</code> repository में जाएँ।</li><li>Post files edit या add करें।</li><li>Changes commit करें।</li><li>ImgBed admin panel पर लौटकर <code>Update Blog</code> click करें, या blog homepage के upper-left corner में logo पर तीन बार click करके blog update trigger करें।</li></ol><p><code>Update Blog</code> आपके लिखे हुए content को overwrite नहीं करता। यह ज़रूरत पड़ने पर repository initialize करता है और blog cache refresh करता है।</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog में post lists, categories, tags, archives, search, dark mode और language switching जैसी common blog features supported हैं।</p><p>Comments और visit statistics भी supported हैं।</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>Comments posts के नीचे दिखते हैं। Visitors avatar, nickname, email और comment content submit कर सकते हैं।</p><p>Visit statistics post views और site visits दिखाते हैं, जिससे blog traffic समझने में मदद मिलती है।</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog हमेशा <code>/blog/</code> के तहत serve होता है।</p><p>उदाहरण के लिए, अगर आपका ImgBed domain है:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>तो blog URL होगा:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Blog disabled होने के बाद visitors blog page access नहीं कर पाएँगे।</p>',34)])])}const k=i(n,[["render",r]]);export{v as __pageData,k as default};
